# Source catalogs and description generators for plane example upgrades.
# ASCII-safe strings for Windows PowerShell 5.x compatibility.

function New-KindTemplates {
    param($Positive, $Boundary, $Counter, $Instance)
    return @{
        positive = $Positive
        boundary = $Boundary
        counterexample = $Counter
        instance = $Instance
    }
}

function Expand-Desc {
    param([scriptblock]$Block, [string]$NodeId)
    $r = & $Block $NodeId
    return @{ zh = $r.zh; en = $r.en; ja = $r.ja }
}

function Get-PlaneDescription {
    param([string]$SourceId, [string]$NodeId, [string]$Kind, [hashtable]$Catalog)
    $templates = $Catalog.Templates[$SourceId]
    if (-not $templates) { throw "Unknown source: $SourceId" }
    $kindKey = if ($templates.ContainsKey($Kind)) { $Kind } else { 'positive' }
    $tpl = $templates[$kindKey]
    return Expand-Desc -Block $tpl -NodeId $NodeId
}

function T {
    param([string]$NodeId, [string]$Zh, [string]$En, [string]$Ja)
    return @{ zh = ($Zh -replace '\{n\}', $NodeId); en = ($En -replace '\{n\}', $NodeId); ja = ($Ja -replace '\{n\}', $NodeId) }
}

