        langsmith = (New-KindTemplates { param($n) T $n 'LangSmith RunTree parent_run_id, run_type chain/llm/tool; tracing_v2_enabled(project_name) chain.invoke(); {n} maps TraceRecord/TraceSpan/Execution.' 'LangSmith RunTree parent_run_id, run_type chain/llm/tool; tracing_v2_enabled chain.invoke(); {n} maps TraceRecord/TraceSpan/Execution.' 'LangSmith RunTree parent_run_id run_type; {n} run tree.' } { param($n) T $n 'run.outputs is trace preview not PROV Entity; {n} must not treat run JSON as Artifact digest.' 'run.outputs is trace preview not PROV Entity; {n} must not treat run JSON as Artifact digest.' 'run.outputs not Artifact.' } { param($n) T $n 'Log without parent_run_id/run_type cannot serve as LangSmith-style {n}.' 'Log without parent_run_id/run_type cannot serve as LangSmith-style {n}.' 'Missing parent_run_id rejects LangSmith-style {n}.' } { param($n) T $n 'LangSmith instance: run_id=0192a3b4 parent_run_id=0192a3b3 run_type=llm->{n}.' 'LangSmith instance: run_id parent_run_id run_type=llm->{n}.' 'LangSmith instance maps to {n}.' })
        langfuse = (New-KindTemplates { param($n) T $n 'Langfuse trace=langfuse.trace(name=''my-agent''); span=trace.span(name=''llm-call'', metadata={model:gpt-4}); trace.score(name=''accuracy'', value=0.95); {n} maps TraceRecord/TraceSpan/ObservabilityEvent.' 'Langfuse trace.span metadata model=gpt-4; trace.score accuracy=0.95; {n} maps TraceRecord/TraceSpan/ObservabilityEvent.' 'Langfuse trace.span+score; {n} TraceRecord/Span.' } { param($n) T $n 'Langfuse score is eval signal not Execution; {n} preserves trace/span/score distinction.' 'Langfuse score is eval signal not Execution; {n} preserves trace/span/score distinction.' 'score not Execution.' } { param($n) T $n 'Generation without trace container cannot serve as Langfuse-style {n} TraceRecord.' 'Generation without trace container cannot serve as Langfuse-style {n} TraceRecord.' 'Missing trace rejects Langfuse-style {n}.' } { param($n) T $n 'Langfuse instance: trace_id=langfuse-0192a3b4 span llm-call score accuracy=0.95->{n}.' 'Langfuse instance: trace+span+score->{n}.' 'Langfuse instance maps to {n}.' })
        arize_phoenix = (New-KindTemplates { param($n) T $n 'Arize Phoenix embedding drift, prompt/response quality, trace viz; {n} maps ObservabilityEvent/MetricSample.' 'Arize Phoenix embedding drift, prompt/response quality, trace viz; {n} maps ObservabilityEvent/MetricSample.' 'Phoenix drift+quality; {n} ObservabilityEvent.' } { param($n) T $n 'p99 latency is ObservableSummary; single span is TraceSpan; {n} must not treat percentile as Execution.' 'p99 latency is ObservableSummary; single span is TraceSpan; {n} must not treat percentile as Execution.' 'p99 aggregate; single span TraceSpan.' } { param($n) T $n 'Latency without embedding_version cannot serve as Phoenix-style {n} drift event.' 'Latency without embedding_version cannot serve as Phoenix-style {n} drift event.' 'Missing embedding_version rejects Phoenix-style {n}.' } { param($n) T $n 'Phoenix instance: embedding_drift_score=0.18 prompt_quality=0.91->{n} ObservabilityEvent.' 'Phoenix instance: drift+quality->{n} ObservabilityEvent.' 'Phoenix instance maps to {n} Event.' })
        helicone = (New-KindTemplates { param($n) T $n 'Helicone LLM proxy replaces base_url to trace API; records latency/cost/model/tokens; {n} maps TraceRecord/Execution/CostMetric.' 'Helicone LLM proxy replaces base_url to trace API; records latency/cost/model/tokens; {n} maps TraceRecord/Execution/CostMetric.' 'Helicone base_url proxy trace; {n} telemetry.' } { param($n) T $n 'cost_usd is cost metric; Execution is bounded run; {n} must not treat proxy log as completed PROV Activity.' 'cost_usd is cost metric; Execution is bounded run; {n} must not treat proxy log as completed PROV Activity.' 'cost metric; not completed Activity.' } { param($n) T $n 'Mock bypassing Helicone gateway cannot serve as Helicone-style {n}.' 'Mock bypassing Helicone gateway cannot serve as Helicone-style {n}.' 'Gateway bypass rejects Helicone-style {n}.' } { param($n) T $n 'Helicone instance: request_id=hc-771 latency_ms=842 cost_usd=0.003 model=gpt-4o->{n}.' 'Helicone instance: request_id latency cost model->{n}.' 'Helicone instance maps to {n} Execution.' })
        vllm = (New-KindTemplates { param($n) T $n 'vLLM python -m vllm.entrypoints.openai.api_server --model meta-llama/Llama-3-8B; PagedAttention+continuous batching; {n} maps RuntimeEnvironment/Execution/GenerativeModel.' 'vLLM api_server --model meta-llama/Llama-3-8B; PagedAttention+continuous batching; {n} maps RuntimeEnvironment/Execution/GenerativeModel.' 'vLLM api_server PagedAttention; {n} serving env.' } { param($n) T $n 'batch scheduler is env state; POST /v1/chat/completions is Execution; {n} preserves env/execution boundary.' 'batch scheduler is env state; POST /v1/chat/completions is Execution; {n} preserves env/execution boundary.' 'scheduler env; API call Execution.' } { param($n) T $n 'Script without model/endpoint cannot serve as vLLM-style {n} RuntimeEnvironment.' 'Script without model/endpoint cannot serve as vLLM-style {n} RuntimeEnvironment.' 'Missing model/endpoint rejects vLLM-style {n}.' } { param($n) T $n 'vLLM instance: env_id=vllm-llama3-8b endpoint=http://127.0.0.1:8000/v1->{n}.' 'vLLM instance: env_id endpoint model->{n} RuntimeEnvironment.' 'vLLM instance maps to {n} RuntimeEnvironment.' })
        ollama = (New-KindTemplates { param($n) T $n 'Ollama ollama run llama3 / ollama serve; POST /api/chat {model:llama3,messages:[...]}; {n} maps RuntimeEnvironment/LocalExecution/ModelActor.' 'Ollama ollama serve; POST /api/chat {model:llama3,messages}; {n} maps RuntimeEnvironment/LocalExecution/ModelActor.' 'Ollama /api/chat model=llama3; {n} local runtime.' } { param($n) T $n 'model manifest is env config; chat completion is Execution; {n} must not treat Modelfile path as Execution result.' 'model manifest is env config; chat completion is Execution; {n} must not treat Modelfile path as Execution result.' 'manifest env; chat completion Execution.' } { param($n) T $n 'Echo without model/messages cannot serve as Ollama-style {n} Execution.' 'Echo without model/messages cannot serve as Ollama-style {n} Execution.' 'Missing model/messages rejects Ollama-style {n}.' } { param($n) T $n 'Ollama instance: POST /api/chat model=llama3->{n} execution_id=ollama-chat-12.' 'Ollama instance: POST /api/chat model=llama3->{n} execution_id=ollama-chat-12.' 'Ollama instance maps to {n} Execution.' })
    }
}

# --- Info plane ---
$Script:InfoCatalog = @{
    SourceIds = @('attention','outlines','vercel_ai_sdk','instructor','perplexity','claude_citations','dspy_signatures')
    DefaultModuleKey = 'info-plane'
    DefaultSources = @('attention','vercel_ai_sdk','claude_citations','dspy_signatures')
    NodeSourceMap = @{
        ContentPart = @('attention','vercel_ai_sdk','claude_citations')
        TextContent = @('attention','vercel_ai_sdk','perplexity')
        StructuredData = @('instructor','outlines','dspy_signatures')
        StructuredDataBlock = @('instructor','outlines','dspy_signatures')
        SourceReference = @('perplexity','claude_citations','attention')
        CitationAnchor = @('perplexity','claude_citations','attention')
        ContentAnchor = @('claude_citations','perplexity','attention')
        SourceProvenance = @('claude_citations','perplexity','attention')
        OutputCitation = @('perplexity','claude_citations','attention')
        PromptTemplate = @('dspy_signatures','instructor','vercel_ai_sdk')
        SystemInstruction = @('dspy_signatures','instructor','attention')
        PromptArgument = @('dspy_signatures','instructor','vercel_ai_sdk')
        OutputSegment = @('vercel_ai_sdk','attention','outlines')
        StandardOutput = @('vercel_ai_sdk','attention','outlines')
        MessageHistory = @('attention','vercel_ai_sdk','claude_citations')
        AssistantMessage = @('vercel_ai_sdk','instructor','attention')
    }
    ModuleSourceMap = @{
        'info-prompts-instructions' = @('dspy_signatures','instructor','vercel_ai_sdk','attention')
        'info-storage-sources' = @('perplexity','claude_citations','attention')
        'info-output-disclosure' = @('vercel_ai_sdk','perplexity','claude_citations')
        'info-content-parts' = @('attention','instructor','outlines')
        'info-content-block-modality' = @('attention','outlines','instructor')
        'info-container-command' = @('vercel_ai_sdk','outlines','attention')
        'info-messages-instructions' = @('attention','vercel_ai_sdk','claude_citations')
        'info-indexing' = @('perplexity','attention','dspy_signatures')
        'info-plane' = @('attention','vercel_ai_sdk','claude_citations','dspy_signatures')
    }
    Templates = @{
        attention = (New-KindTemplates { param($n) T $n 'Attention Is All You Need (Vaswani et al., 2017) self-attention Q/K/V scaled dot-product; context window is transformer sequence foundation; {n} maps ContentPart/token boundaries.' 'Attention Is All You Need (Vaswani et al., 2017) self-attention Q/K/V; context window is transformer sequence foundation; {n} maps ContentPart/token boundaries.' 'Attention self-attention Q/K/V; {n} context/token boundary.' } { param($n) T $n 'context length is model constraint; {n} records info structure; KV cache is not SourceReference.' 'context length is model constraint; {n} records info structure; KV cache is not SourceReference.' 'KV cache not SourceReference.' } { param($n) T $n 'Bare text without sequence_index/token boundary cannot serve as attention-style {n}.' 'Bare text without sequence_index/token boundary cannot serve as attention-style {n}.' 'Missing boundary rejects attention-style {n}.' } { param($n) T $n 'Attention instance: max_context_tokens=8192 sequence_index=42->{n} addressable segment.' 'Attention instance: max_context_tokens=8192 sequence_index=42->{n} addressable segment.' 'Attention instance maps to {n}.' })
        outlines = (New-KindTemplates { param($n) T $n 'Outlines (Willard & Louf, 2023) FSM: model.generate(prompt, regex=r''\d{3}-\d{2}-\d{4}'') or JSON schema; {n} maps StructuredContent/OutputFormat.' 'Outlines (Willard & Louf, 2023) FSM regex or JSON schema; {n} maps StructuredContent/OutputFormat.' 'Outlines FSM/regex; {n} StructuredContent.' } { param($n) T $n 'Outlines constraint is OutputFormat spec; unvalidated JSON is not StructuredData; {n} preserves spec/wire boundary.' 'Outlines constraint is OutputFormat spec; unvalidated JSON is not StructuredData; {n} preserves spec/wire boundary.' 'Unvalidated JSON not StructuredData.' } { param($n) T $n 'Free text without schema/regex cannot serve as Outlines-style {n} StructuredData.' 'Free text without schema/regex cannot serve as Outlines-style {n} StructuredData.' 'Missing schema/regex rejects Outlines-style {n}.' } { param($n) T $n 'Outlines instance: regex SSN validated output->{n} StructuredData schema_ref=ssn-regex-v1.' 'Outlines instance: regex SSN validated output->{n} StructuredData.' 'Outlines instance maps to {n} StructuredData.' })
        vercel_ai_sdk = (New-KindTemplates { param($n) T $n 'Vercel AI SDK streamText({model:openai(''gpt-4''),prompt})->textStream; for await chunk of textStream; {n} maps StreamingOutput/OutputRepresentation.' 'Vercel AI SDK streamText->textStream; for await chunk of textStream; {n} maps StreamingOutput/OutputRepresentation.' 'Vercel AI SDK streamText textStream chunk; {n} StreamingOutput.' } { param($n) T $n 'textStream chunk is OutputSegment event; complete AssistantMessage is terminal; {n} must not treat partial delta as final Message.' 'textStream chunk is OutputSegment event; complete AssistantMessage is terminal; {n} must not treat partial delta as final Message.' 'Partial delta not final Message.' } { param($n) T $n 'HTTP response without stream protocol/chunk index cannot serve as Vercel AI SDK-style {n} StreamingOutput.' 'HTTP response without stream protocol/chunk index cannot serve as Vercel AI SDK-style {n} StreamingOutput.' 'Missing chunk index rejects Vercel AI SDK-style {n}.' } { param($n) T $n 'Vercel AI SDK instance: stream chunks->{n} OutputSegment sequence_index=0,1.' 'Vercel AI SDK instance: stream chunks->{n} OutputSegment sequence_index=0,1.' 'Vercel AI SDK instance maps to {n} OutputSegment.' })
        instructor = (New-KindTemplates { param($n) T $n 'Instructor client=instructor.from_openai(OpenAI()); create(response_model=User, messages=[...]) Pydantic validation; {n} maps StructuredContent/OutputFormat type-safe parsing.' 'Instructor from_openai; create(response_model=User, messages) Pydantic validation; {n} maps StructuredContent/OutputFormat type-safe parsing.' 'Instructor response_model=User Pydantic; {n} StructuredContent.' } { param($n) T $n 'response_model is OutputFormat spec; raw JSON is wire; {n} records validated structured entity.' 'response_model is OutputFormat spec; raw JSON is wire; {n} records validated structured entity.' 'response_model spec; raw JSON wire.' } { param($n) T $n 'JSON without response_model/validation cannot serve as Instructor-style {n} StructuredData.' 'JSON without response_model/validation cannot serve as Instructor-style {n} StructuredData.' 'Missing response_model rejects Instructor-style {n}.' } { param($n) T $n 'Instructor instance: validated User->{n} StructuredData content_type=application/json.' 'Instructor instance: validated User->{n} StructuredData.' 'Instructor instance maps to {n} StructuredData.' })
        perplexity = (New-KindTemplates { param($n) T $n 'Perplexity inline [1] links to search results; citations[] url/snippet; {n} maps Citation/SourceReference clickable anchors.' 'Perplexity inline [1] links to search results; citations[] url/snippet; {n} maps Citation/SourceReference clickable anchors.' 'Perplexity [1]+citations url; {n} Citation/SourceReference.' } { param($n) T $n '[1] is CitationAnchor; full SourceReference needs url+digest; {n} must not treat hallucinated URL as verified source.' '[1] is CitationAnchor; full SourceReference needs url+digest; {n} must not treat hallucinated URL as verified source.' 'Hallucinated URL not verified source.' } { param($n) T $n '[1] without citations/url cannot serve as Perplexity-style {n} SourceReference.' '[1] without citations/url cannot serve as Perplexity-style {n} SourceReference.' 'Missing citations/url rejects Perplexity-style {n}.' } { param($n) T $n 'Perplexity instance: answer [1] citations url->{n} CitationAnchor index=1.' 'Perplexity instance: answer [1] citations url->{n} CitationAnchor index=1.' 'Perplexity instance maps to {n} CitationAnchor.' })
        claude_citations = (New-KindTemplates { param($n) T $n 'Claude Citations API citations=[{type:char_location, cited_text, document_index, start_char_index, end_char_index}]; supports document/URL/plain text; {n} maps Citation/ContentAnchor/SourceProvenance.' 'Claude Citations API char_location start/end_char_index document_index; {n} maps Citation/ContentAnchor/SourceProvenance.' 'Claude Citations char_location start/end; {n} ContentAnchor.' } { param($n) T $n 'char_location is ContentAnchor; SourceProvenance is attribution chain; {n} must not treat document_index alone as full SourceReference.' 'char_location is ContentAnchor; SourceProvenance is attribution chain; {n} must not treat document_index alone as full SourceReference.' 'document_index alone not full SourceReference.' } { param($n) T $n 'cited_text without start/end_char_index cannot serve as Claude Citations-style {n} ContentAnchor.' 'cited_text without start/end_char_index cannot serve as Claude Citations-style {n} ContentAnchor.' 'Missing char index rejects Claude Citations-style {n}.' } { param($n) T $n 'Claude Citations instance: char_location start=10 end=50 cited_text=self-attention->{n} ContentAnchor.' 'Claude Citations instance: char_location start/end cited_text->{n} ContentAnchor.' 'Claude Citations instance maps to {n} ContentAnchor.' })
        dspy_signatures = (New-KindTemplates { param($n) T $n 'DSPy Signatures ''context, question -> answer''; RAGAnswer(dspy.Signature) InputField/OutputField; {n} maps PromptTemplate/SystemInstruction/PromptVariable field contracts.' 'DSPy Signatures ''context, question -> answer''; RAGAnswer(dspy.Signature) InputField/OutputField; {n} maps PromptTemplate/SystemInstruction/PromptVariable field contracts.' 'DSPy Signature InputField/OutputField; {n} PromptTemplate.' } { param($n) T $n 'Signature is PromptTemplate spec; compiled prompt is runtime instance; {n} must not treat optimized demo as SystemInstruction authority.' 'Signature is PromptTemplate spec; compiled prompt is runtime instance; {n} must not treat optimized demo as SystemInstruction authority.' 'Signature spec; compiled prompt runtime.' } { param($n) T $n 'Ad-hoc prompt without InputField/OutputField cannot serve as DSPy-style {n} PromptTemplate.' 'Ad-hoc prompt without InputField/OutputField cannot serve as DSPy-style {n} PromptTemplate.' 'Missing InputField/OutputField rejects DSPy-style {n}.' } { param($n) T $n 'DSPy instance: Signature->PromptTemplate variable_names=[context, question]->{n}.' 'DSPy instance: Signature->PromptTemplate variable_names=[context, question]->{n}.' 'DSPy instance maps to {n} PromptTemplate.' })
    }
}
